import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import io from 'socket.io-client';
import {
  Box,
  Container,
  Paper,
  TextField,
  IconButton,
  Avatar,
  Typography,
  Drawer,
  List,
  ListItem,
  ListItemAvatar,
  ListItemText,
  Badge,
  Divider,
  Toolbar,
  AppBar,
  Button,
  Chip,
  CircularProgress,
  Fab,
  InputAdornment,
  Tooltip,
  Menu,
  MenuItem,
  ListItemIcon
} from '@mui/material';
import SendIcon from '@mui/icons-material/Send';
import LogoutIcon from '@mui/icons-material/Logout';
import PeopleIcon from '@mui/icons-material/People';
import SearchIcon from '@mui/icons-material/Search';
import AddIcon from '@mui/icons-material/Add';
import MoreVertIcon from '@mui/icons-material/MoreVert';
import LockIcon from '@mui/icons-material/Lock';
import GroupIcon from '@mui/icons-material/Group';
import PersonAddIcon from '@mui/icons-material/PersonAdd';
import SettingsIcon from '@mui/icons-material/Settings';
import dayjs from 'dayjs';
import relativeTime from 'dayjs/plugin/relativeTime';
import { toast } from 'react-hot-toast';

// Dayjs plugin
dayjs.extend(relativeTime);

// Message Bubble Component
const MessageBubble = ({ message, isOwn, showSender }) => (
  <Box
    sx={{
      display: 'flex',
      justifyContent: isOwn ? 'flex-end' : 'flex-start',
      mb: 2,
      px: 2
    }}
  >
    <Box sx={{ maxWidth: '70%', display: 'flex', flexDirection: 'column' }}>
      {!isOwn && showSender && (
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 0.5, ml: 1 }}>
          <Avatar
            sx={{
              width: 20,
              height: 20,
              fontSize: '0.7rem',
              bgcolor: message.userColor || '#7289da',
              mr: 1
            }}
          >
            {message.userName?.charAt(0) || 'A'}
          </Avatar>
          <Typography variant="caption" sx={{ color: 'text.secondary', fontWeight: 'bold' }}>
            {message.userName}
          </Typography>
        </Box>
      )}
      <Paper
        elevation={1}
        sx={{
          p: 1.5,
          backgroundColor: isOwn ? 'primary.main' : 'background.paper',
          color: isOwn ? 'primary.contrastText' : 'text.primary',
          borderRadius: 2,
          borderTopLeftRadius: isOwn ? 12 : 2,
          borderTopRightRadius: isOwn ? 2 : 12,
          position: 'relative',
          '&:hover': {
            boxShadow: 2
          }
        }}
      >
        <Typography variant="body1" sx={{ wordBreak: 'break-word' }}>
          {message.message}
        </Typography>
        <Typography
          variant="caption"
          sx={{
            display: 'block',
            textAlign: 'right',
            mt: 0.5,
            opacity: 0.7,
            fontSize: '0.7rem'
          }}
        >
          {dayjs(message.timestamp).format('HH:mm')}
        </Typography>
      </Paper>
    </Box>
  </Box>
);

// User List Component
const UserList = ({ users, onSelectUser }) => (
  <List sx={{ width: '100%' }}>
    {users.map((user, index) => (
      <ListItem
        key={user.id || index}
        button
        onClick={() => onSelectUser(user)}
        sx={{
          mb: 1,
          borderRadius: 1,
          '&:hover': {
            backgroundColor: 'action.hover'
          }
        }}
      >
        <ListItemAvatar>
          <Badge
            color="success"
            variant="dot"
            invisible={!user.online}
            anchorOrigin={{
              vertical: 'bottom',
              horizontal: 'right'
            }}
          >
            <Avatar sx={{ bgcolor: user.avatarColor || '#7289da' }}>
              {user.name?.charAt(0) || 'U'}
            </Avatar>
          </Badge>
        </ListItemAvatar>
        <ListItemText
          primary={
            <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
              {user.name}
            </Typography>
          }
          secondary={
            <Typography variant="caption" color="text.secondary">
              {user.online ? 'Online' : 'Offline'}
            </Typography>
          }
        />
        {user.unreadCount > 0 && (
          <Chip
            label={user.unreadCount}
            size="small"
            color="primary"
            sx={{ minWidth: 24, height: 24 }}
          />
        )}
      </ListItem>
    ))}
  </List>
);

const ChatPage = () => {
  const navigate = useNavigate();
  const [socket, setSocket] = useState(null);
  const [connected, setConnected] = useState(false);
  const [user, setUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [roomId, setRoomId] = useState('general');
  const [typingUsers, setTypingUsers] = useState({});
  const [loading, setLoading] = useState(true);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [rooms, setRooms] = useState([]);
  const [anchorEl, setAnchorEl] = useState(null);
  
  const messagesEndRef = useRef(null);
  const typingTimeoutRef = useRef(null);
  const messageContainerRef = useRef(null);

  // Initialize user and socket
  useEffect(() => {
    const storedUser = localStorage.getItem('user');
    if (!storedUser) {
      navigate('/login');
      return;
    }

    try {
      const userData = JSON.parse(storedUser);
      setUser(userData);

      // Initialize Socket.io
      const socketInstance = io('http://localhost:5000', {
        transports: ['websocket', 'polling'],
        reconnection: true,
        reconnectionAttempts: 5
      });

      socketInstance.on('connect', () => {
        console.log('✅ Connected to WebSocket');
        setConnected(true);
        
        // Join default room
        socketInstance.emit('join_room', {
          userId: userData.id,
          roomId: 'general'
        });
        
        toast.success('Connected to chat server');
      });

      socketInstance.on('connect_error', (error) => {
        console.error('❌ Connection error:', error);
        toast.error('Connection failed. Trying to reconnect...');
        setConnected(false);
      });

      socketInstance.on('receive_message', (message) => {
        if (message.roomId === roomId) {
          setMessages(prev => [...prev, message]);
          
          // Play notification sound for new messages
          if (message.userId !== userData.id) {
            playNotificationSound();
          }
        }
      });

      socketInstance.on('user_typing', (data) => {
        if (data.roomId === roomId) {
          setTypingUsers(prev => ({
            ...prev,
            [data.userId]: data
          }));
          
          // Clear typing indicator after 3 seconds
          setTimeout(() => {
            setTypingUsers(prev => {
              const newTyping = { ...prev };
              delete newTyping[data.userId];
              return newTyping;
            });
          }, 3000);
        }
      });

      socketInstance.on('user_joined', (data) => {
        console.log('User joined:', data);
        setOnlineUsers(prev => [...prev, {
          id: data.userId,
          name: `Anonymous_${Math.floor(1000 + Math.random() * 9000)}`,
          online: true
        }]);
      });

      socketInstance.on('user_left', (data) => {
        setOnlineUsers(prev => prev.filter(u => u.id !== data.userId));
      });

      setSocket(socketInstance);
      setLoading(false);

      // Load sample data
      loadSampleData();

      return () => {
        socketInstance.disconnect();
      };
    } catch (error) {
      console.error('Error initializing chat:', error);
      toast.error('Failed to initialize chat');
      navigate('/login');
    }
  }, [navigate]);

  // Load sample data
  const loadSampleData = () => {
    const sampleMessages = [
      {
        id: '1',
        roomId: 'general',
        userId: 'system',
        userName: 'System',
        userColor: '#43b581',
        message: 'Welcome to Canfezz Chat! Your messages are end-to-end encrypted.',
        timestamp: new Date(Date.now() - 3600000).toISOString()
      },
      {
        id: '2',
        roomId: 'general',
        userId: 'guest_1',
        userName: 'Anonymous_1234',
        userColor: '#7289da',
        message: 'Hello everyone! How is the chat working?',
        timestamp: new Date(Date.now() - 1800000).toISOString()
      },
      {
        id: '3',
        roomId: 'general',
        userId: 'guest_2',
        userName: 'Anonymous_5678',
        userColor: '#faa61a',
        message: 'Working great! The encryption is seamless.',
        timestamp: new Date(Date.now() - 900000).toISOString()
      }
    ];

    const sampleUsers = [
      { id: 'guest_1', name: 'Anonymous_1234', avatarColor: '#7289da', online: true },
      { id: 'guest_2', name: 'Anonymous_5678', avatarColor: '#faa61a', online: true },
      { id: 'guest_3', name: 'Anonymous_9101', avatarColor: '#43b581', online: false },
      { id: 'guest_4', name: 'Anonymous_1121', avatarColor: '#f04747', online: true }
    ];

    const sampleRooms = [
      { id: 'general', name: 'General Chat', unreadCount: 0, lastMessage: 'Welcome!' },
      { id: 'random', name: 'Random', unreadCount: 3, lastMessage: 'Anyone here?' },
      { id: 'help', name: 'Help & Support', unreadCount: 0, lastMessage: 'Need help?' }
    ];

    setMessages(sampleMessages);
    setOnlineUsers(sampleUsers);
    setRooms(sampleRooms);
  };

  // Scroll to bottom when messages change
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Send message
  const sendMessage = useCallback(() => {
    if (!inputMessage.trim() || !socket || !connected || !user) return;

    const messageData = {
      roomId,
      message: inputMessage.trim(),
      userId: user.id,
      userName: user.displayName,
      userColor: user.avatarColor
    };

    socket.emit('send_message', messageData);

    // Add to local state immediately
    const tempMessage = {
      ...messageData,
      id: `temp_${Date.now()}`,
      timestamp: new Date().toISOString()
    };

    setMessages(prev => [...prev, tempMessage]);
    setInputMessage('');
    
    // Clear typing indicator
    clearTyping();
  }, [inputMessage, socket, connected, user, roomId]);

  // Handle typing
  const handleTyping = useCallback(() => {
    if (!socket || !connected || !user) return;

    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }

    socket.emit('typing', {
      roomId,
      userId: user.id,
      userName: user.displayName,
      isTyping: true
    });

    typingTimeoutRef.current = setTimeout(() => {
      socket.emit('typing', {
        roomId,
        userId: user.id,
        userName: user.displayName,
        isTyping: false
      });
    }, 2000);
  }, [socket, connected, user, roomId]);

  // Clear typing
  const clearTyping = useCallback(() => {
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }
    
    if (socket && connected && user) {
      socket.emit('typing', {
        roomId,
        userId: user.id,
        userName: user.displayName,
        isTyping: false
      });
    }
  }, [socket, connected, user, roomId]);

  // Scroll to bottom
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // Handle key press
  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  // Play notification sound
  const playNotificationSound = () => {
    try {
      const audio = new Audio('https://assets.mixkit.co/sfx/preview/mixkit-correct-answer-tone-2870.mp3');
      audio.volume = 0.3;
      audio.play();
    } catch (error) {
      console.log('Audio notification failed:', error);
    }
  };

  // Logout
  const handleLogout = () => {
    localStorage.removeItem('user');
    localStorage.removeItem('token');
    if (socket) {
      socket.disconnect();
    }
    navigate('/login');
  };

  // Create new chat
  const handleNewChat = () => {
    const newRoomId = `room_${Date.now()}`;
    setRoomId(newRoomId);
    setMessages([]);
    
    if (socket && connected && user) {
      socket.emit('join_room', {
        userId: user.id,
        roomId: newRoomId
      });
    }
    
    toast.success('Created new private chat');
  };

  // Handle menu open
  const handleMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  // Handle menu close
  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  // Get typing indicator text
  const getTypingText = () => {
    const typing = Object.values(typingUsers);
    if (typing.length === 0) return null;
    
    if (typing.length === 1) {
      return `${typing[0].userName} is typing...`;
    }
    
    if (typing.length === 2) {
      return `${typing[0].userName} and ${typing[1].userName} are typing...`;
    }
    
    return `${typing.length} people are typing...`;
  };

  // Handle user selection (FIXED - no toast.info)
  const onSelectUser = (selectedUser) => {
    toast(`Starting chat with ${selectedUser.name}`, {
      icon: '💬',
      style: {
        background: '#36393f',
        color: '#fff',
      },
    });
  };

  // Handle menu item clicks (FIXED)
  const handleMenuItemClick = (action) => {
    handleMenuClose();
    switch(action) {
      case 'settings':
        toast('Settings coming soon!', {
          icon: '⚙️',
          style: {
            background: '#7289da',
            color: '#fff',
          },
        });
        break;
      case 'new_group':
        toast('Group chat feature coming soon!', {
          icon: '👥',
          style: {
            background: '#43b581',
            color: '#fff',
          },
        });
        break;
      case 'theme':
        toast('Theme switcher coming soon!', {
          icon: '🎨',
          style: {
            background: '#faa61a',
            color: '#fff',
          },
        });
        break;
    }
  };

  if (loading) {
    return (
      <Box sx={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        flexDirection: 'column',
        gap: 2
      }}>
        <CircularProgress size={60} />
        <Typography variant="h6" color="text.secondary">
          Connecting to secure chat...
        </Typography>
      </Box>
    );
  }

  return (
    <Box sx={{ display: 'flex', height: '100vh', overflow: 'hidden' }}>
      {/* Sidebar */}
      <Drawer
        variant="permanent"
        sx={{
          width: 280,
          flexShrink: 0,
          '& .MuiDrawer-paper': {
            width: 280,
            boxSizing: 'border-box',
            backgroundColor: '#2f3136',
            borderRight: '1px solid #40444b'
          }
        }}
      >
        {/* Sidebar Header */}
        <Toolbar sx={{ borderBottom: '1px solid #40444b' }}>
          <Box sx={{ display: 'flex', alignItems: 'center', width: '100%' }}>
            <Avatar sx={{ bgcolor: user?.avatarColor || '#7289da', mr: 2 }}>
              {user?.displayName?.charAt(0) || 'A'}
            </Avatar>
            <Box sx={{ flexGrow: 1 }}>
              <Typography variant="subtitle1" sx={{ fontWeight: 'bold' }}>
                {user?.displayName}
              </Typography>
              <Chip
                label={connected ? 'Online' : 'Offline'}
                size="small"
                color={connected ? 'success' : 'error'}
                sx={{ height: 20, fontSize: '0.7rem' }}
              />
            </Box>
            <IconButton onClick={handleMenuOpen} size="small">
              <MoreVertIcon />
            </IconButton>
          </Box>
        </Toolbar>

        {/* Menu */}
        <Menu
          anchorEl={anchorEl}
          open={Boolean(anchorEl)}
          onClose={handleMenuClose}
        >
          <MenuItem onClick={handleNewChat}>
            <ListItemIcon>
              <AddIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText>New Chat</ListItemText>
          </MenuItem>
          <MenuItem onClick={() => handleMenuItemClick('new_group')}>
            <ListItemIcon>
              <GroupIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText>New Group</ListItemText>
          </MenuItem>
          <MenuItem onClick={() => handleMenuItemClick('settings')}>
            <ListItemIcon>
              <SettingsIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText>Settings</ListItemText>
          </MenuItem>
          <Divider />
          <MenuItem onClick={handleLogout}>
            <ListItemIcon>
              <LogoutIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText>Logout</ListItemText>
          </MenuItem>
        </Menu>

        {/* Search */}
        <Box sx={{ p: 2 }}>
          <TextField
            fullWidth
            size="small"
            placeholder="Search chats..."
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <SearchIcon sx={{ color: 'text.secondary' }} />
                </InputAdornment>
              )
            }}
            sx={{
              '& .MuiOutlinedInput-root': {
                backgroundColor: '#202225',
                '& fieldset': {
                  borderColor: 'transparent'
                },
                '&:hover fieldset': {
                  borderColor: '#40444b'
                }
              }
            }}
          />
        </Box>

        {/* Rooms */}
        <Box sx={{ px: 2, mb: 2 }}>
          <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 'bold', mb: 1, display: 'block' }}>
            CHANNELS
          </Typography>
          <List dense>
            {rooms.map((room) => (
              <ListItem
                key={room.id}
                button
                selected={roomId === room.id}
                onClick={() => setRoomId(room.id)}
                sx={{
                  borderRadius: 1,
                  mb: 0.5,
                  '&.Mui-selected': {
                    backgroundColor: '#7289da',
                    '&:hover': {
                      backgroundColor: '#677bc4'
                    }
                  }
                }}
              >
                <ListItemText
                  primary={`# ${room.name}`}
                  primaryTypographyProps={{
                    variant: 'body2',
                    fontWeight: roomId === room.id ? 'bold' : 'normal'
                  }}
                />
                {room.unreadCount > 0 && (
                  <Chip
                    label={room.unreadCount}
                    size="small"
                    color="primary"
                    sx={{ minWidth: 20, height: 20, fontSize: '0.65rem' }}
                  />
                )}
              </ListItem>
            ))}
          </List>
        </Box>

        {/* Online Users */}
        <Box sx={{ px: 2, flexGrow: 1 }}>
          <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 'bold', mb: 1, display: 'block' }}>
            ONLINE - {onlineUsers.filter(u => u.online).length}
          </Typography>
          <UserList
            users={onlineUsers}
            onSelectUser={onSelectUser}
          />
        </Box>

        {/* New Chat Button */}
        <Box sx={{ p: 2 }}>
          <Tooltip title="Start New Private Chat">
            <Button
              fullWidth
              variant="contained"
              startIcon={<PersonAddIcon />}
              onClick={handleNewChat}
              sx={{
                backgroundColor: '#43b581',
                '&:hover': {
                  backgroundColor: '#3ca374'
                }
              }}
            >
              New Chat
            </Button>
          </Tooltip>
        </Box>
      </Drawer>

      {/* Main Chat Area */}
      <Box sx={{ flexGrow: 1, display: 'flex', flexDirection: 'column' }}>
        {/* Chat Header */}
        <AppBar
          position="static"
          color="default"
          elevation={0}
          sx={{
            backgroundColor: '#36393f',
            borderBottom: '1px solid #40444b',
            zIndex: 1
          }}
        >
          <Toolbar>
            <GroupIcon sx={{ mr: 2, color: '#b9bbbe' }} />
            <Box sx={{ flexGrow: 1 }}>
              <Typography variant="h6">
                {roomId === 'general' ? 'General Chat' : 'Private Chat'}
              </Typography>
              <Typography variant="caption" color="text.secondary">
                {getTypingText() || `${onlineUsers.filter(u => u.online).length} online`}
              </Typography>
            </Box>
            <Chip
              icon={<LockIcon sx={{ fontSize: 14 }} />}
              label="End-to-End Encrypted"
              size="small"
              color="success"
              variant="outlined"
              sx={{ mr: 2 }}
            />
            <Fab
              color="primary"
              size="small"
              onClick={scrollToBottom}
              sx={{ boxShadow: 'none' }}
            >
              <SendIcon />
            </Fab>
          </Toolbar>
        </AppBar>

        {/* Messages Container */}
        <Box
          ref={messageContainerRef}
          sx={{
            flexGrow: 1,
            overflowY: 'auto',
            backgroundColor: '#36393f',
            backgroundImage: 'radial-gradient(circle at 1px 1px, #40444b 1px, transparent 0)',
            backgroundSize: '20px 20px'
          }}
        >
          {messages.length === 0 ? (
            <Box sx={{ 
              display: 'flex', 
              flexDirection: 'column', 
              alignItems: 'center', 
              justifyContent: 'center',
              height: '100%',
              color: 'text.secondary',
              textAlign: 'center',
              p: 4
            }}>
              <LockIcon sx={{ fontSize: 80, mb: 2, opacity: 0.5 }} />
              <Typography variant="h5" gutterBottom>
                Secure Chat Room
              </Typography>
              <Typography variant="body1" sx={{ maxWidth: 400, mb: 3 }}>
                This is a secure, end-to-end encrypted chat room. Your messages are private and cannot be read by anyone else.
              </Typography>
              <Button
                variant="contained"
                startIcon={<SendIcon />}
                onClick={() => setInputMessage('Hello! 👋')}
              >
                Say Hello
              </Button>
            </Box>
          ) : (
            <>
              {/* Welcome Message */}
              <Box sx={{ p: 3, textAlign: 'center', color: 'text.secondary' }}>
                <Typography variant="caption">
                  {dayjs(messages[0]?.timestamp).format('MMMM D, YYYY')}
                </Typography>
                <Typography variant="h6" sx={{ mt: 1 }}>
                  Welcome to #{roomId === 'general' ? 'General' : 'Private'} Chat
                </Typography>
              </Box>

              {/* Messages */}
              {messages.map((message, index) => {
                const isOwn = message.userId === user?.id;
                const showSender = index === 0 || 
                  messages[index - 1]?.userId !== message.userId ||
                  dayjs(message.timestamp).diff(messages[index - 1]?.timestamp, 'minute') > 5;
                
                return (
                  <MessageBubble
                    key={message.id}
                    message={message}
                    isOwn={isOwn}
                    showSender={showSender}
                  />
                );
              })}
              <div ref={messagesEndRef} />
            </>
          )}
        </Box>

        {/* Message Input */}
        <Box sx={{ p: 2, backgroundColor: '#36393f', borderTop: '1px solid #40444b' }}>
          <Box sx={{ display: 'flex', gap: 1, alignItems: 'flex-end' }}>
            <TextField
              fullWidth
              multiline
              maxRows={4}
              placeholder={`Message #${roomId === 'general' ? 'general' : 'private'}...`}
              value={inputMessage}
              onChange={(e) => {
                setInputMessage(e.target.value);
                handleTyping();
              }}
              onKeyPress={handleKeyPress}
              variant="outlined"
              size="small"
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: '#40444b',
                  '& fieldset': {
                    borderColor: 'transparent'
                  },
                  '&:hover fieldset': {
                    borderColor: '#7289da'
                  },
                  '&.Mui-focused fieldset': {
                    borderColor: '#7289da'
                  }
                },
                '& .MuiInputBase-input': {
                  color: 'white'
                }
              }}
            />
            <IconButton
              color="primary"
              onClick={sendMessage}
              disabled={!inputMessage.trim() || !connected}
              sx={{
                backgroundColor: inputMessage.trim() ? '#7289da' : '#40444b',
                color: 'white',
                '&:hover': {
                  backgroundColor: inputMessage.trim() ? '#677bc4' : '#40444b'
                },
                height: 40,
                width: 40
              }}
            >
              <SendIcon />
            </IconButton>
          </Box>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 1 }}>
            <Typography variant="caption" color="text.secondary">
              {connected ? '🔒 Encrypted • Press Enter to send' : '🔌 Connecting...'}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {messages.length} messages
            </Typography>
          </Box>
        </Box>
      </Box>
    </Box>
  );
};

export default ChatPage;
